import{_ as a,o as t,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const v=JSON.parse('{"title":"92. Advertising Vacancies","description":"","frontmatter":{"title":"92. Advertising Vacancies","eba":"Allied Health Professionals 2021-2026","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/92-advertising-vacancies.md","filePath":"ebas/allied-health/classification-staffing/92-advertising-vacancies.md"}'),s={name:"ebas/allied-health/classification-staffing/92-advertising-vacancies.md"};function o(r,e,c,l,h,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_92-advertising-vacancies" tabindex="-1">92. Advertising Vacancies <a class="header-anchor" href="#_92-advertising-vacancies" aria-label="Permalink to &quot;92. Advertising Vacancies&quot;">​</a></h1><p><strong>92.1</strong> Where a vacancy arises within the Employer, the Employer will advertise the vacant position or available hours, internally in the first instance and then externally if necessary:</p><p><strong>(a)</strong> where a vacancy will arise at the end of the notice of termination, immediately after giving notice of termination (by either the Employee or Employer); or</p><p><strong>(b)</strong> where a vacancy will not arise immediately after the end of the notice, such as where the Employee’s role has been backfilled, as soon as practicable.</p><p><strong>92.2</strong> The Employer will advertise all vacancies that arise where the vacancy relates to a position that, but for the vacancy occurring, would have been ongoing.</p><p><strong>92.3</strong> The Employer will appoint someone to a vacant position as soon as practicable.</p>',6)])])}const f=a(s,[["render",o]]);export{v as __pageData,f as default};
